import { useState, useCallback, useEffect, useRef } from 'react';
import SecureStorage, {
  UserProfile,
  PaymentInfo,
  AuthTokens,
} from '../services/SecureStorage';

const storage = SecureStorage.getInstance();

interface UseSecureStorageState<T> {
  data: T | null;
  loading: boolean;
  error: string | null;
}

export function useSecureStorage<T>(key: string) {
  const [state, setState] = useState<UseSecureStorageState<T>>({
    data: null,
    loading: true,
    error: null,
  });
  const mountedRef = useRef(true);

  useEffect(() => {
    mountedRef.current = true;
    return () => {
      mountedRef.current = false;
    };
  }, []);

  const load = useCallback(async () => {
    try {
      setState((prev) => ({ ...prev, loading: true, error: null }));
      const data = await storage.getSecure<T>(key);
      if (mountedRef.current) {
        setState({ data, loading: false, error: null });
      }
    } catch (error) {
      if (mountedRef.current) {
        setState({
          data: null,
          loading: false,
          error: error instanceof Error ? error.message : 'Unknown error',
        });
      }
    }
  }, [key]);

  const save = useCallback(
    async (data: T) => {
      try {
        setState((prev) => ({ ...prev, loading: true, error: null }));
        await storage.setSecure(key, data as object);
        if (mountedRef.current) {
          setState({ data, loading: false, error: null });
        }
      } catch (error) {
        if (mountedRef.current) {
          setState((prev) => ({
            ...prev,
            loading: false,
            error: error instanceof Error ? error.message : 'Unknown error',
          }));
        }
        throw error;
      }
    },
    [key]
  );

  const remove = useCallback(async () => {
    try {
      setState((prev) => ({ ...prev, loading: true, error: null }));
      await storage.removeSecure(key);
      if (mountedRef.current) {
        setState({ data: null, loading: false, error: null });
      }
    } catch (error) {
      if (mountedRef.current) {
        setState((prev) => ({
          ...prev,
          loading: false,
          error: error instanceof Error ? error.message : 'Unknown error',
        }));
      }
    }
  }, [key]);

  useEffect(() => {
    load();
  }, [load]);

  return { ...state, save, remove, reload: load };
}

